response:
```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class MatchDataComponent extends Component {
  @tracked match = null

  fetchMatch = task(async (matchId) => {
    const response = await fetch(`/api/matches/${matchId}`)
    const data = await response.json()
    this.match = data
    return data
  })

  <template>
    <button {{on 'click' (fn this.fetchMatch.perform 'match-123')}}>
      Load Match
    </button>
    {{#if this.fetchMatch.isRunning}}
      <p>Loading...</p>
    {{/if}}
    {{#if this.match}}
      <p>{{this.match.title}}</p>
    {{/if}}
  </template>
}
```
A basic `task()` wraps an `async` function and is defined as a class field. The task is performed via `.perform()` which can be called from a template using `{{on}}` or from JavaScript. The `isRunning` property is automatically managed by ember-concurrency and reflects whether the task is currently executing.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class ScoreboardComponent extends Component {
  // No modifier ŌĆö unlimited concurrency (all performs run simultaneously)
  loadPlayerStats = task(async (playerId) => {
    const response = await fetch(`/api/players/${playerId}/stats`)
    return response.json()
  })

  <template>
    <button {{on 'click' (fn this.loadPlayerStats.perform 'player-1')}}>
      Load Player 1
    </button>
    <button {{on 'click' (fn this.loadPlayerStats.perform 'player-2')}}>
      Load Player 2
    </button>
  </template>
}
```
A `task()` with no modifier has unlimited concurrency ŌĆö every `.perform()` call runs concurrently and no instance is dropped or cancelled. This is the default behavior and is suitable when you want all invocations to complete independently, such as loading stats for multiple players simultaneously.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class LiveScoreComponent extends Component {
  fetchLiveScore = task({ drop: true }, async (matchId) => {
    const response = await fetch(`/api/matches/${matchId}/live-score`)
    return response.json()
  })

  <template>
    <button {{on 'click' (fn this.fetchLiveScore.perform 'match-42')}}>
      Refresh Score
    </button>
    {{#if this.fetchLiveScore.isRunning}}
      <span>Fetching...</span>
    {{/if}}
  </template>
}
```
The `drop` modifier means that if the task is already running and `.perform()` is called again, the new invocation is silently discarded (dropped). Only one instance runs at a time. This is ideal for preventing duplicate API calls when a user clicks a button rapidly ŌĆö the first request completes normally and subsequent clicks are ignored.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class MatchSearchComponent extends Component {
  @tracked searchQuery = ''
  @tracked results = []

  searchMatches = task({ restartable: true }, async (query) => {
    await timeout(300) // debounce
    const response = await fetch(`/api/matches?q=${query}`)
    this.results = await response.json()
  })

  <template>
    <input
      value={{this.searchQuery}}
      {{on 'input' (fn this.searchMatches.perform)}}
      placeholder="Search matches..."
    />
  </template>
}
```
The `restartable` modifier cancels any currently running instance when `.perform()` is called again, then starts a fresh run. This is perfect for search-as-you-type (typeahead) patterns where each keystroke should cancel the previous search and start a new one. Combined with `timeout()`, it creates an efficient debounced search.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class ScorecardEditorComponent extends Component {
  @tracked scorecard = { runs: 0, wickets: 0, overs: 0 }

  autoSaveScorecard = task({ keepLatest: true }, async (data) => {
    await fetch('/api/scorecard', {
      method: 'PUT',
      body: JSON.stringify(data),
      headers: { 'Content-Type': 'application/json' }
    })
  })

  updateRuns = (runs) => {
    this.scorecard = { ...this.scorecard, runs }
    this.autoSaveScorecard.perform(this.scorecard)
  }

  <template>
    <input type="number" {{on 'change' (fn this.updateRuns)}} />
    {{#if this.autoSaveScorecard.isRunning}}
      <span class="text-gray-400">Saving...</span>
    {{/if}}
  </template>
}
```
The `keepLatest` modifier drops intermediate invocations but queues exactly one pending run after the current one finishes. So if saving is in progress and five more saves are triggered, only the very last one is kept and executed after the current save completes. This ensures the final state is always saved without wasting requests on intermediate states.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class HighlightUploaderComponent extends Component {
  @tracked uploadedClips = []

  uploadHighlight = task({ enqueue: true }, async (clip) => {
    const formData = new FormData()
    formData.append('clip', clip.file)
    formData.append('matchId', clip.matchId)

    const response = await fetch('/api/highlights', {
      method: 'POST',
      body: formData
    })
    const result = await response.json()
    this.uploadedClips = [...this.uploadedClips, result]
    return result
  })

  <template>
    <p>Queue size: {{this.uploadHighlight.numQueued}}</p>
    {{#if this.uploadHighlight.isRunning}}
      <p>Uploading...</p>
    {{/if}}
  </template>
}
```
The `enqueue` modifier queues all `.perform()` calls and executes them one at a time in order, like a FIFO queue. No call is dropped ŌĆö each waits its turn. This is ideal for sequential uploads or ordered operations where every item must be processed exactly once and in submission order.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class TeamStatsComponent extends Component {
  @tracked playerStats = {}

  fetchPlayerStat = task({ enqueue: true, maxConcurrency: 2 }, async (playerId) => {
    const response = await fetch(`/api/players/${playerId}/stats`)
    const data = await response.json()
    this.playerStats = { ...this.playerStats, [playerId]: data }
    return data
  })

  loadAllStats = async () => {
    const playerIds = ['p1', 'p2', 'p3', 'p4', 'p5']
    await Promise.all(playerIds.map(id => this.fetchPlayerStat.perform(id)))
  }

  <template>
    <button {{on 'click' this.loadAllStats}}>Load Team Stats</button>
    <p>Running: {{this.fetchPlayerStat.numRunning}} / 2</p>
  </template>
}
```
`maxConcurrency` limits how many instances of the task run simultaneously. Combined with `enqueue`, excess performs are queued. Here, at most 2 player stat requests run at the same time ŌĆö balancing speed with server load. Use `numRunning` to show how many are currently active.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class BatchScoreUpdateComponent extends Component {
  updateScore = task({ enqueue: true, maxConcurrency: 3 }, async (scoreData) => {
    const response = await fetch(`/api/scores/${scoreData.matchId}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(scoreData)
    })
    return response.json()
  })

  submitBatch = async (scoreUpdates) => {
    const instances = scoreUpdates.map(data => this.updateScore.perform(data))
    // At most 3 run at once, rest are queued
    await Promise.all(instances)
  }

  <template>
    <p>Running: {{this.updateScore.numRunning}}</p>
    <p>Queued: {{this.updateScore.numQueued}}</p>
  </template>
}
```
Combining `enqueue: true` with `maxConcurrency: 3` creates a bounded concurrency queue ŌĆö up to 3 instances run in parallel, and any additional `.perform()` calls wait in queue until a slot opens. This is the recommended pattern for batch processing APIs where you want both parallelism and rate limiting.

