}

// Ō£ģ CORRECT ŌĆö use the {{did-insert}} modifier or a dedicated start action
import { modifier } from 'ember-modifier'

export default class CorrectScoreLoader extends Component {
  @tracked score = null

  fetchScore = task(async () => {
    const res = await fetch(`/api/matches/${this.args.matchId}/score`)
    if (!res.ok) throw new Error('Score fetch failed')
    this.score = await res.json()
