import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class ScoreParser extends Component {
  @tracked score = null

  fetchAndParseScore = task(async () => {
    let response
    try {
      response = await fetch(`/api/matches/${this.args.matchId}/score`)
    } catch (networkErr) {
      throw new Error(`Network error: ${networkErr.message}`)
    }

    if (!response.ok) {
      throw new Error(`HTTP ${response.status}: ${response.statusText}`)
    }

    let data
    try {
      data = await response.json()
    } catch (parseErr) {
      throw new Error(`Invalid JSON from server: ${parseErr.message}`)
    }

    if (typeof data.runs !== 'number') {
      throw new Error('Unexpected response shape ŌĆö runs field missing')
    }

    this.score = data
  })

  <template>
    <button type="button" {{on "click" (fn this.fetchAndParseScore.perform)}}>
      Fetch Score
    </button>
    {{#if this.fetchAndParseScore.last.error}}
      <p class="text-red-500">{{this.fetchAndParseScore.last.error.message}}</p>
    {{/if}}
    {{#if this.score}}
      <p>{{this.score.runs}} / {{this.score.wickets}}</p>
    {{/if}}
  </template>
}
```
Separating network errors, HTTP errors, JSON parse errors, and schema validation into distinct `try/catch` blocks or `if` checks gives much more actionable error messages than a single catch-all. This level of error granularity is expected in production code and in Google L5 coding interviews.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class AbortableFetcher extends Component {
  @tracked matchData = null

  fetchMatch = task(async () => {
    const controller = new AbortController()
    const { signal } = controller

    try {
      const response = await fetch(
        `/api/matches/${this.args.matchId}`,
        { signal }
      )
      if (!response.ok) throw new Error('Fetch failed')
      this.matchData = await response.json()
    } finally {
      // This runs even if the task is cancelled
      // AbortController is already handled by the browser via signal
    }

    return this.matchData
  })

  cancel = () => this.fetchMatch.cancelAll()

  <template>
    <button type="button" {{on "click" (fn this.fetchMatch.perform)}}>
      Fetch Match
    </button>
    <button type="button" {{on "click" this.cancel}}>Cancel</button>
    {{#if this.matchData}}
      <p>{{this.matchData.title}}</p>
    {{/if}}
  </template>
}
```
Passing an `AbortController` signal to `fetch()` allows the browser to cancel the underlying HTTP request when ember-concurrency cancels the task. Without `AbortController`, cancelling the task stops JS execution but the HTTP request continues to the server. The `finally` block runs cleanup even when the task is cancelled mid-await.

