export default class LiveScoreComponent extends Component {
  @tracked runs = this.args.match.runs
  @tracked wickets = this.args.match.wickets

  addRuns = task(async (matchId, runsToAdd) => {
    // Optimistic update ŌĆö change UI immediately
    const previousRuns = this.runs
    this.runs = this.runs + runsToAdd

    try {
      const response = await fetch(`/api/matches/${matchId}/score`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ runs: this.runs }),
      })
      if (!response.ok) throw new Error('Score update failed')
    } catch (err) {
      // Rollback on failure
      this.runs = previousRuns
      throw err
    }
  })

  <template>
    <p>Score: {{this.runs}} / {{this.wickets}}</p>
    <button type="button" {{on "click" (fn this.addRuns.perform @match.id 4)}}>
      +4
    </button>
  </template>
}
```

Optimistic updates improve perceived performance by reflecting changes in the UI instantly. The previous value is saved before the update. A `try/catch` inside the task rolls back the local state if the API call fails. This pattern is especially effective in a live scoring app where speed of feedback matters more than strict consistency.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class MatchStateComponent extends Component {
  @tracked match = { ...this.args.match }
  #snapshot = null

  saveMatch = task(async (updates) => {
    // Take a snapshot before applying changes
    this.#snapshot = { ...this.match }
    Object.assign(this.match, updates)
    // Trigger reactivity by reassigning
    this.match = { ...this.match }

    try {
      const response = await fetch(`/api/matches/${this.match.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(this.match),
      })
      if (!response.ok) throw new Error('Save failed')
      this.#snapshot = null
    } catch (err) {
      // Restore from snapshot
      if (this.#snapshot) {
        this.match = this.#snapshot
        this.#snapshot = null
      }
      throw err
    }
  })

  <template>
    <p>Venue: {{this.match.venue}}</p>
    <button
      type="button"
      {{on "click" (fn this.saveMatch.perform { venue: 'Lords Cricket Ground' })}}
    >
      Update Venue
    </button>
    {{#if this.saveMatch.last.error}}
      <p class="text-red-500">Failed ŌĆö reverted to previous state</p>
    {{/if}}
  </template>
}
```

A private class field `#snapshot` holds the pre-update state. If the API call throws, the snapshot is restored to `this.match` and the field is cleared. The private field is inaccessible from the template, keeping rollback logic fully encapsulated inside the component class.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class RetryScoreComponent extends Component {
  @tracked score = null

  fetchWithRetry = task(async (matchId, maxRetries = 3) => {
    let attempt = 0
    while (attempt < maxRetries) {
      try {
        const response = await fetch(`/api/matches/${matchId}/score`)
        if (!response.ok) throw new Error(`HTTP ${response.status}`)
        this.score = await response.json()
        return this.score
      } catch (err) {
        attempt++
        if (attempt >= maxRetries) throw new Error(`Failed after ${maxRetries} attempts: ${err.message}`)
        await timeout(500 * attempt) // Exponential backoff: 500ms, 1000ms, 1500ms
      }
    }
  })

  <template>
    <button type="button" {{on "click" (fn this.fetchWithRetry.perform @matchId)}}>
      {{if this.fetchWithRetry.isRunning 'Retrying...' 'Fetch Score'}}
    </button>
    {{#if this.fetchWithRetry.last.error}}
      <p class="text-red-500">{{this.fetchWithRetry.last.error.message}}</p>
    {{/if}}
  </template>
}
```

The `while` loop tracks `attempt` count and uses `timeout()` from ember-concurrency for cancellation-aware delays between retries. The backoff multiplier (`500 * attempt`) gives progressively longer waits. On the final attempt the error is re-thrown, transitioning the task to an error state visible in the template via `last.error`.

