import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class CircuitBreakerComponent extends Component {
  @tracked score = null
  @tracked circuitOpen = false
  #failureCount = 0
  static #THRESHOLD = 5
  static #RESET_AFTER = 30_000 // 30 seconds

  fetchScore = task(async (matchId) => {
    if (this.circuitOpen) {
      throw new Error('Circuit open ŌĆö too many failures. Try again later.')
    }
    try {
      const response = await fetch(`/api/matches/${matchId}/score`)
      if (!response.ok) throw new Error(`HTTP ${response.status}`)
      this.score = await response.json()
      this.#failureCount = 0 // Reset on success
      return this.score
    } catch (err) {
      this.#failureCount++
      if (this.#failureCount >= CircuitBreakerComponent.#THRESHOLD) {
        this.circuitOpen = true
        setTimeout(() => {
          this.circuitOpen = false
          this.#failureCount = 0
        }, CircuitBreakerComponent.#RESET_AFTER)
      }
      throw err
    }
  })

  <template>
    {{#if this.circuitOpen}}
      <p class="text-orange-500">Service unavailable ŌĆö circuit open. Retrying in 30s.</p>
    {{else}}
      <button type="button" {{on "click" (fn this.fetchScore.perform @matchId)}}>
        Fetch Score
      </button>
    {{/if}}
  </template>
}
```

The circuit breaker pattern prevents cascading failures by refusing to attempt API calls after `#THRESHOLD` consecutive errors. Private class fields (`#failureCount`, `#THRESHOLD`) encapsulate the circuit state. After `#RESET_AFTER` milliseconds the circuit closes again ŌĆö a half-open retry window. This protects downstream services from being hammered during outages.

