import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class ThrottledScoreComponent extends Component {
  @tracked score = null
  @tracked throttled = false

  refreshScore = task({ drop: true }, async (matchId) => {
    if (this.throttled) return // Guard for non-task callers
    this.throttled = true

    try {
      const response = await fetch(`/api/matches/${matchId}/score`)
      if (!response.ok) throw new Error('Refresh failed')
      this.score = await response.json()
    } finally {
      await timeout(5000)
      this.throttled = false
    }
  })

  <template>
    <button
      type="button"
      disabled={{or this.refreshScore.isRunning this.throttled}}
      {{on "click" (fn this.refreshScore.perform @matchId)}}
    >
      {{if this.throttled 'Wait 5s...' 'Refresh Score'}}
    </button>
    {{#if this.score}}
      <p>{{this.score.runs}} / {{this.score.wickets}}</p>
    {{/if}}
  </template>
}
```

`{ drop: true }` prevents concurrent task instances from stacking up. The `@tracked throttled` flag blocks re-triggering for 5 seconds after the request completes. Using `finally` ensures the timeout always runs even if the fetch throws, so the throttle always resets. The button's `disabled` attribute checks both `isRunning` and `throttled` to cover the cooldown period after the request finishes.

