import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class DualFeedComponent extends Component {
  @tracked liveData = null
  @tracked archiveData = null
  @tracked mode = 'live' // 'live' | 'archive'

  liveFeed = task(async (matchId) => {
    this.mode = 'live'
    while (this.mode === 'live') {
      const response = await fetch(`/api/matches/${matchId}/live`)
      if (!response.ok) break
      this.liveData = await response.json()
      await timeout(3000)
    }
  })

  archiveFeed = task(async (matchId) => {
    this.mode = 'archive' // This stops liveFeed's while loop
    this.liveFeed.cancelAll()
    const response = await fetch(`/api/matches/${matchId}/archive`)
    if (!response.ok) throw new Error('Archive load failed')
    this.archiveData = await response.json()
  })

  <template>
    <button type="button" {{on "click" (fn this.liveFeed.perform @matchId)}}>
      Live Feed
    </button>
    <button type="button" {{on "click" (fn this.archiveFeed.perform @matchId)}}>
      Archive Mode
    </button>
  </template>
}
```

The `@tracked mode` flag acts as a cooperative cancellation signal. The `liveFeed` task's `while` loop checks `this.mode` each iteration and exits cleanly when it changes. `archiveFeed` also calls `this.liveFeed.cancelAll()` to immediately cancel any in-flight `await` inside `liveFeed`, ensuring no stale requests are left running.

