import Route from '@ember/routing/route'
import { task } from 'ember-concurrency'
import { service } from '@ember/service'

export default class MatchRoute extends Route {
  @service session
  @service router

  checkAuth = task(async () => {
    const isAuthenticated = await this.session.validate()
    if (!isAuthenticated) {
      this.router.transitionTo('login')
    }
  })

  async beforeModel(transition) {
    await this.checkAuth.perform()
  }

  async model({ match_id }) {
    const response = await fetch(`/api/matches/${match_id}`)
    if (!response.ok) throw new Error('Match not found')
    return response.json()
  }
}
