export default class TournamentRoute extends Route {
  loadTournament = task(async (tournamentId) => {
    const [tournamentRes, fixturesRes] = await Promise.all([
      fetch(`/api/tournaments/${tournamentId}`),
      fetch(`/api/tournaments/${tournamentId}/fixtures`),
    ])
    if (!tournamentRes.ok || !fixturesRes.ok) {
      throw new Error('Failed to load tournament data')
