import Route from '@ember/routing/route'
import { task } from 'ember-concurrency'
import { action } from '@ember/object'

export default class EditMatchRoute extends Route {
  @tracked hasUnsavedChanges = false

  confirmNavigation = task(async (transition) => {
    if (!this.hasUnsavedChanges) {
      transition.retry()
      return
    }
    const confirmed = await new Promise((resolve) => {
      // Replace with a proper modal in production
      resolve(window.confirm('You have unsaved changes. Leave anyway?'))
    })
    if (confirmed) {
      this.hasUnsavedChanges = false
      transition.retry()
    } else {
      transition.abort()
    }
  })

  @action
  willTransition(transition) {
    if (this.hasUnsavedChanges) {
      transition.abort()
      this.confirmNavigation.perform(transition)
    }
  }
}
```

The `willTransition` action aborts navigation immediately when there are unsaved changes, then defers to the `confirmNavigation` task to show an async confirmation dialog. The task wraps `window.confirm` (or a modal) in a Promise so it integrates cleanly with `await`. On confirmation the original transition is retried; on rejection it stays aborted.

