      disabled={{this.downloadReport.isRunning}}
      {{on "click" (fn this.downloadReport.perform @matchId)}}
    >
      {{if this.downloadReport.isRunning 'Downloading...' 'Download Report'}}
    </button>
  </template>
}
```

The task fetches the PDF as a `Blob`, creates a temporary object URL via `URL.createObjectURL`, then programmatically clicks a hidden anchor element to trigger the browser's download dialog. `URL.revokeObjectURL` is called after a short delay to free memory once the download is initiated. This approach works without any server-side redirect.

