import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class RetryWithSleepComponent extends Component {
  @tracked score = null

  fetchScoreWithDelay = task(async (matchId) => {
    const delays = [1000, 2000, 4000] // 1s, 2s, 4s exponential backoff

    for (const [index, delay] of delays.entries()) {
      try {
        const response = await fetch(`/api/matches/${matchId}/score`)
        if (!response.ok) throw new Error(`HTTP ${response.status}`)
        this.score = await response.json()
        return this.score
      } catch (err) {
        const isLast = index === delays.length - 1
        if (isLast) throw new Error(`All retries exhausted: ${err.message}`)
        // Sleep before next retry
        await timeout(delay)
      }
    }
  })

  <template>
    <button type="button" {{on "click" (fn this.fetchScoreWithDelay.perform @matchId)}}>
      {{if this.fetchScoreWithDelay.isRunning 'Trying...' 'Fetch Score'}}
    </button>
  </template>
}
```

`timeout(ms)` from ember-concurrency is preferable to `new Promise(resolve => setTimeout(resolve, ms))` because it is cancellation-aware ŌĆö if the task is cancelled while sleeping, it will not resume after the delay. Using an array of delays makes the backoff strategy explicit and easy to modify without changing loop logic.

