import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

const validateScore = ({ runs, wickets, overs }) => {
  const errors = []
  if (typeof runs !== 'number' || runs < 0) errors.push('Runs must be a non-negative number')
  if (typeof wickets !== 'number' || wickets < 0 || wickets > 10) errors.push('Wickets must be 0ŌĆō10')
  if (typeof overs !== 'number' || overs < 0 || overs > 50) errors.push('Overs must be 0ŌĆō50')
  return errors
}

export default class ScoreSubmitComponent extends Component {
  @tracked validationErrors = []

  submitScore = task(async (matchId, scoreData) => {
    const errors = validateScore(scoreData)
    if (errors.length > 0) {
      this.validationErrors = errors
      throw new Error(`Validation failed: ${errors.join(', ')}`)
    }
    this.validationErrors = []
    const response = await fetch(`/api/matches/${matchId}/score`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(scoreData),
    })
    if (!response.ok) throw new Error('Score submission failed')
    return response.json()
  })

  <template>
    {{#each this.validationErrors as |error|}}
      <p class="text-red-500">{{error}}</p>
    {{/each}}
    <button type="button"
      {{on "click" (fn this.submitScore.perform @matchId (hash runs=287 wickets=6 overs=50))}}
    >
      Submit Score
    </button>
  </template>
}
```

Validation runs synchronously before any network call, so invalid data is caught immediately without wasting a round trip. The `validateScore` function returns an array of error messages, which are stored in `@tracked validationErrors` for template rendering. Throwing inside the task transitions it to an error state, ensuring callers of `.perform()` can also observe the failure via `last.error`.

