import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class MatchVideoComponent extends Component {
  @tracked videoSrc = null

  loadVideo = task(async (matchId) => {
    const response = await fetch(`/api/matches/${matchId}/highlights.mp4`)
    if (!response.ok) throw new Error('Video load failed')
    const blob = await response.blob()
    const objectUrl = URL.createObjectURL(blob)
    this.videoSrc = objectUrl

    try {
      // Simulate processing or waiting for user interaction
      await new Promise((resolve) => {
        // Resolve after 5 minutes or when task is cancelled
        setTimeout(resolve, 5 * 60 * 1000)
      })
    } finally {
      // Always revoke the object URL to prevent memory leaks
      URL.revokeObjectURL(objectUrl)
      this.videoSrc = null
    }
  })

  <template>
    <button type="button" {{on "click" (fn this.loadVideo.perform @matchId)}}>
      Load Highlights
    </button>
    {{#if this.videoSrc}}
      <video src={{this.videoSrc}} controls></video>
    {{/if}}
  </template>
}
```

The `finally` block inside a task runs whether the task completes normally, throws, or is cancelled. This makes it the correct place for cleanup code like `URL.revokeObjectURL` ŌĆö it guarantees no memory leaks regardless of the execution path. If the task is cancelled (e.g., component destroyed), the `finally` block still executes before the task terminates.

