import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class AnalyticsScoreComponent extends Component {
  @tracked score = null

  fetchAndMeasure = task(async (matchId) => {
    const start = performance.now()
    let latencyMs = null

    try {
      const response = await fetch(`/api/matches/${matchId}/score`)
      latencyMs = Math.round(performance.now() - start)
      if (!response.ok) throw new Error(`HTTP ${response.status}`)
      this.score = await response.json()
      return this.score
    } finally {
      if (latencyMs !== null) {
        // Fire-and-forget analytics beacon ŌĆö don't await
        fetch('/api/analytics/latency', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            endpoint: `/api/matches/${matchId}/score`,
            latencyMs,
            timestamp: new Date().toISOString(),
          }),
        }).catch(() => {}) // Silently ignore analytics errors
      }
    }
  })

  <template>
    <button type="button" {{on "click" (fn this.fetchAndMeasure.perform @matchId)}}>
      Fetch Score
    </button>
  </template>
}
```

`performance.now()` gives sub-millisecond precision compared to `Date.now()`. The analytics beacon is fired as a fire-and-forget POST inside `finally` ŌĆö it is not awaited so it doesn't block the task's completion. The `.catch(() => {})` silently swallows analytics errors to prevent them from propagating into the main task flow.

