    await timeout(1000) // Wait 1 second after last keystroke
    const response = await fetch(`/api/matches/${matchId}/draft`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ notes: content }),
    })
