    this.lastSaved = new Date().toLocaleTimeString()
  })

  @action
  onInput(matchId, event) {
    this.notes = event.target.value
    this.saveDraft.perform(matchId, this.notes)
  }

  <template>
    <textarea
      value={{this.notes}}
      {{on "input" (fn this.onInput @matchId)}}
      placeholder="Match notes..."
    ></textarea>
    {{#if this.saveDraft.isRunning}}
      <span class="text-gray-400">Saving...</span>
